/**
 * Task report module.
 */

export interface Task {
  title: string;
  done: boolean;
  hours: number;
}

export interface ReportInput {
  title: string;
  tasks: Task[];
}

const DEFAULT_THEME = {
  separator: "=",
  bullet: "-",
  doneMarker: "[x]",
  openMarker: "[ ]",
} as const;

const MESSAGES = {
  en: {
    done: "done",
    total: "total",
    doneLabel: "Done",
    openLabel: "Open",
    hoursLabel: "Hours",
  },
} as const;

interface RenderContext {
  readonly input: ReportInput;
  readonly separator: string;
  readonly bullet: string;
  readonly theme: typeof DEFAULT_THEME;
  readonly messages: (typeof MESSAGES)["en"];
}

interface SectionRenderer {
  readonly section: string;
  render(context: RenderContext): string[];
}

class HeaderRenderer implements SectionRenderer {
  readonly section = "header";

  render(context: RenderContext): string[] {
    const title = context.input.title;
    const underline = context.separator.repeat(title.length);
    return [title, underline];
  }
}

class TaskListRenderer implements SectionRenderer {
  readonly section = "tasks";

  render(context: RenderContext): string[] {
    return context.input.tasks.map((task) => {
      const marker = task.done ? context.theme.doneMarker : context.theme.openMarker;
      return `${context.bullet} ${marker} ${task.title} (${task.hours}h)`;
    });
  }
}

class SummaryRenderer implements SectionRenderer {
  readonly section = "summary";

  render(context: RenderContext): string[] {
    let doneCount = 0;
    let openCount = 0;
    let totalHours = 0;
    for (const task of context.input.tasks) {
      if (task.done) doneCount += 1;
      else openCount += 1;
      totalHours += task.hours;
    }
    return [
      `${context.messages.doneLabel}: ${doneCount}`,
      `${context.messages.openLabel}: ${openCount}`,
      `${context.messages.hoursLabel}: ${totalHours}h`,
    ];
  }
}

class FooterRenderer implements SectionRenderer {
  readonly section = "footer";

  render(context: RenderContext): string[] {
    let doneCount = 0;
    let totalHours = 0;
    for (const task of context.input.tasks) {
      if (task.done) doneCount += 1;
      totalHours += task.hours;
    }
    const total = context.input.tasks.length;
    return [`${doneCount}/${total} ${context.messages.done}, ${totalHours}h ${context.messages.total}`];
  }
}

function createRenderers(): Map<string, SectionRenderer> {
  const renderers = new Map<string, SectionRenderer>();
  renderers.set("header", new HeaderRenderer());
  renderers.set("tasks", new TaskListRenderer());
  renderers.set("summary", new SummaryRenderer());
  renderers.set("footer", new FooterRenderer());
  return renderers;
}

interface EngineHooks {
  beforeSection?(section: string): void;
  afterSection?(section: string, lines: string[]): void;
}

class RenderingEngine {
  constructor(
    private readonly renderers: Map<string, SectionRenderer>,
    private readonly hooks: EngineHooks,
  ) {}

  renderSections(sections: string[], context: RenderContext): string[] {
    const lines: string[] = [];
    for (const section of sections) {
      this.hooks.beforeSection?.(section);
      const renderer = this.renderers.get(section);
      if (!renderer) throw new Error(`no renderer for section: ${section}`);
      const sectionLines = renderer.render(context);
      lines.push(...sectionLines);
      this.hooks.afterSection?.(section, sectionLines);
    }
    return lines;
  }
}

export interface ReportOptions {
  separator?: string;
  bullet?: string;
  sections?: string[];
  theme?: string;
  locale?: string;
  outputFormat?: "text";
}

const DEFAULT_REPORT_OPTIONS: Required<ReportOptions> = {
  separator: "=",
  bullet: "-",
  sections: ["header", "tasks", "footer"],
  theme: "default",
  locale: "en",
  outputFormat: "text",
};

class ReportBuilder {
  private readonly engine: RenderingEngine;
  private readonly options: Required<ReportOptions>;

  constructor(options?: ReportOptions) {
    this.engine = new RenderingEngine(createRenderers(), {});
    this.options = { ...DEFAULT_REPORT_OPTIONS, ...(options ?? {}) };
  }

  build(input: ReportInput): string {
    if (this.options.theme !== "default") throw new Error(`no theme registered under: ${this.options.theme}`);
    if (this.options.locale !== "en") throw new Error(`no messages for locale: ${this.options.locale}`);

    const context: RenderContext = {
      input,
      separator: this.options.separator,
      bullet: this.options.bullet,
      theme: DEFAULT_THEME,
      messages: MESSAGES.en,
    };
    return this.engine.renderSections(this.options.sections, context).join("\n");
  }
}

export function formatReport(input: ReportInput, options?: ReportOptions): string {
  return new ReportBuilder(options).build(input);
}

